def main():
    with open(DATA_PATH, 'r', encoding='utf-8') as f:
        data = json.load(f)
    id_map = {item['id']: item for item in data}
    updated = 0
    for entry in BATCH:
        target_id = entry['id']
        if target_id not in id_map:
            print(f'WARNING: {target_id} not found')
            continue
        target = id_map[target_id]
        for key, value in entry.items():
            if key == 'id': continue
            old_len = len(target.get(key, ''))
            target[key] = value
            print(f'  {target_id}.{key}: {old_len} → {len(value)}')
        updated += 1
    with open(DATA_PATH, 'w', encoding='utf-8') as f:
        json.dump(data, f, ensure_ascii=False, indent=2)
    print(f'\nUpdated {updated} ingredients')

if __name__ == '__main__':
    main()
